"use strict";(self.webpackChunkdocs=self.webpackChunkdocs||[]).push([[3825],{37346:e=>{e.exports=JSON.parse('{"functions":[{"name":"new","desc":"Constructs a new `HammerController` for the given tool [Model] and [RoundCharacterController]","params":[{"name":"instance","desc":"","lua_type":"Model"},{"name":"roundCharController","desc":"","lua_type":"RoundCharacterController"}],"returns":[{"desc":"","lua_type":"HammerController"}],"function_type":"static","source":{"line":178,"path":"src/Client/Classes/ToolController/HammerController.luau"}},{"name":"Unequip","desc":"Overrides [ToolController:Unequip] to reset the hammer controller\'s block-related variables.","params":[],"returns":[],"function_type":"method","tags":["Override"],"private":true,"source":{"line":203,"path":"src/Client/Classes/ToolController/HammerController.luau"}},{"name":"ActivatePrimary","desc":"Overrides [ToolController:ActivatePrimary] to delete the block the player is pointing at.\\nIf \'toActivate\' is true, the hammer will continuously delete blocks until the method is called again with \'toActivate\' set to false.","params":[{"name":"toActivate","desc":"","lua_type":"boolean"}],"returns":[],"function_type":"method","tags":["Override"],"source":{"line":219,"path":"src/Client/Classes/ToolController/HammerController.luau"}},{"name":"ActivateSecondary","desc":"Overrides [ToolController:ActivateSecondary] to place a block at the position the player is pointing at.\\nIf \'toActivate\' is true, the hammer will continuously place blocks until the method is called again with \'toActivate\' set to false.","params":[{"name":"toActivate","desc":"","lua_type":"boolean"}],"returns":[],"function_type":"method","tags":["Override"],"source":{"line":231,"path":"src/Client/Classes/ToolController/HammerController.luau"}},{"name":"_init","desc":"Overrides [ToolController:_init] to generate the [HammerConfig] and create the `_preview\' [BasePart].","params":[{"name":"instance","desc":"","lua_type":"Model"},{"name":"roundCharController","desc":"","lua_type":"RoundCharacterController"}],"returns":[],"function_type":"method","tags":["Override"],"private":true,"source":{"line":244,"path":"src/Client/Classes/ToolController/HammerController.luau"}},{"name":"_deleteBlock","desc":"If `toDelete` is true, the hammer will continuously delete any `_targetBlock` until the method is called again with `toDelete` set to false.","params":[{"name":"toDelete","desc":"","lua_type":"boolean"}],"returns":[],"function_type":"method","private":true,"source":{"line":288,"path":"src/Client/Classes/ToolController/HammerController.luau"}},{"name":"_placeBlock","desc":"If `toPlace` is true, the hammer will continuously place blocks at the `_placePos` until the method is called again with `toPlace` set to false.","params":[{"name":"toPlace","desc":"","lua_type":"boolean"}],"returns":[],"function_type":"method","private":true,"source":{"line":319,"path":"src/Client/Classes/ToolController/HammerController.luau"}},{"name":"_onPreRender","desc":"Processes pre-render updates, casting a ray to determine the player\'s target block and place position according to the grid.","params":[],"returns":[],"function_type":"method","private":true,"source":{"line":350,"path":"src/Client/Classes/ToolController/HammerController.luau"}}],"properties":[{"name":"_config","desc":"The [HammerConfig] generated from the [Configuration] found in the hammer controller\'s `Instance`.","lua_type":"HammerConfig","private":true,"source":{"line":95,"path":"src/Client/Classes/ToolController/HammerController.luau"}},{"name":"_toDelete","desc":"Whether the player is currently trying to delete blocks.","lua_type":"boolean","private":true,"source":{"line":101,"path":"src/Client/Classes/ToolController/HammerController.luau"}},{"name":"_toPlace","desc":"Whether the player is currently trying to place blocks.","lua_type":"boolean","private":true,"source":{"line":107,"path":"src/Client/Classes/ToolController/HammerController.luau"}},{"name":"_placePos","desc":"The position where the player is trying to place a block.","lua_type":"Vector3?","private":true,"source":{"line":113,"path":"src/Client/Classes/ToolController/HammerController.luau"}},{"name":"_targetBlock","desc":"The [BasePart] block the player is currently targeting for deletion.","lua_type":"BasePart?","private":true,"source":{"line":119,"path":"src/Client/Classes/ToolController/HammerController.luau"}},{"name":"_preview","desc":"A non-collidable, transparent [BasePart] the `_selectionBox` is adorned to.","lua_type":"BasePart","private":true,"source":{"line":125,"path":"src/Client/Classes/ToolController/HammerController.luau"}},{"name":"_selectionBox","desc":"The [SelectionBox] used to visualize the player\'s target on the grid.","lua_type":"SelectionBox","private":true,"source":{"line":131,"path":"src/Client/Classes/ToolController/HammerController.luau"}}],"types":[],"name":"HammerController","desc":"HammerController extends [ToolController] to manage the functionality of a hammer tool within the game. \\nIt allows players to place and delete blocks in a grid-based environment while providing real-time visual \\nfeedback with a [SelectionBox]. The class integrates tightly with the grid system to ensure accurate placement and \\ndeletion of blocks, while also enforcing gameplay rules such as team-based block restrictions and distance limits.\\n\\n### Core Features:\\n- **Block Placement**: Enables players to place blocks at specified grid-aligned positions, ensuring the placement is \\n  valid and free of obstructions.\\n- **Block Deletion**: Allows players to target and delete blocks within their grid-aligned area of interaction.\\n- **Real-Time Feedback**: Displays a [SelectionBox] to indicate the player\'s target position and interaction area.\\n- **Grid Integration**: Utilizes the grid system to align placement and deletion actions to the game environment\'s structure.\\n- **Turf Restrictions**: Ensures actions respect team turf boundaries, preventing block placement or deletion outside the player\'s \\n  allowed area.\\n\\n### Server Interaction:\\n- The `_placeBlock` method fires the `PlaceBlock` [RemoteFunction] to request block placement validation and synchronization.\\n- The `_deleteBlock` method fires the `DeleteBlock` [RemoteEvent] to notify the server about a block deletion request.\\n- These remotes are handled by the [RoundPlayerHandler], which:\\n  - Validates all actions to ensure compliance with gameplay rules, such as grid alignment, turf ownership, and obstruction checks.\\n  - Updates the server-side game state and synchronizes changes with other clients.\\n\\n### Highlights:\\n- Implements the `ActivatePrimary` and `ActivateSecondary` methods to manage block deletion and placement, respectively.\\n- Uses [RunService.PreRender] updates to provide responsive and accurate targeting feedback based on the player\'s camera and position.\\n- Leverages dependency injection for integration with the associated [RoundCharacterController].\\n- Ensures all client actions are validated server-side to maintain game integrity and fairness.\\n\\n### Implementation Notes:\\n- The `Blocks` and `Lines` folders in the [Workspace] must be correctly structured for the class to function as expected.","tags":["ToolController"],"source":{"line":166,"path":"src/Client/Classes/ToolController/HammerController.luau"}}')}}]);